function normalizeData(posts) {
  const authors = {};
  const normalizedPosts = posts.map(post => {
    const { author, ...postData } = post;
    authors[author.id] = author; // store author separately
    return { ...postData, authorId: author.id };
  });

  return { posts: normalizedPosts, authors };
}

const normalized = normalizeData(posts);
